    case "dopoledne":  return "dopoledne";
    case "poledne":    return "poledne";
    case "odpoledne":  return "odpoledne";
    case "podvečer":   return "pozdní odpoledne";
    case "večer":      return "večer";
    case "noc":        return "hluboká noc";
